# Generated by: Claude Sonnet 4.6
#
# ProgressWindow: a child-process Qt window that displays kwin_restore.py
# log output in real time, with a Verbose checkbox and an Abort/Close button.
#
# Architecture
# ────────────
# The Qt window runs entirely in a child process (multiprocessing, spawn
# method).  The parent (kwin_restore.py) communicates with it via:
#
#   cmd_queue    (Queue)       parent → child: log messages, set_complete
#   verbose_val  (Value 'b')   child → parent: Verbose checkbox state
#   abort_val    (Value 'b')   child → parent: Abort button pressed
#   ready_event  (Event)       child → parent: window is visible and ready
#
# A QTimer in the child drains cmd_queue every 50 ms and updates the display.
#
# After the window appears, a best-effort KWin D-Bus script sets
# onAllDesktops=true so the window remains visible while the restore
# switches between virtual desktops.
#
# When progress_window in config.yaml contains a screen alias, the parent
# calls win.move_to_screen(connector) after win.show(), which also sets
# keepBelow=true.  The window is minimized at the end of Phase 4 and raised
# (keepBelow cleared) at the end of Phase 5.
#
# Usage (from kwin_restore.py)
# ─────────────────────────────
#   win    = ProgressWindow()
#   win.show(initial_verbose=args.verbose)   # spawns child, blocks until ready
#   win.move_to_screen("HDMI-A-1")           # optional: move + keepBelow
#   logger = ProgressWindowLogger(win)
#   logger.head("=== KWin Layout Restore ===")
#   logger.info("Phase 1 ...")
#   logger.ok("Done")
#   win.minimize_window()                    # end of Phase 4
#   win.raise_to_front()                     # end of Phase 5
#   win.set_complete()                       # Abort → Close button
#   win.wait_for_close()                     # blocks until user dismisses
#
# ProgressWindowLogger mirrors every message to both the terminal and the
# window.  When win=None it writes to the terminal only — no code changes
# are needed at call sites when the window is disabled.
